class Solution:
    def canPartitionKSubsets(self, nums: List[int], k: int) -> bool:
        total = sum(nums)
        if total % k != 0:
            return False
        target = total // k
        nums.sort(reverse=True)
        if nums[0] > target:
            return False

        def dfs(groups):
            if not nums:
                return True
            v = nums.pop(0)
            for i, group in enumerate(groups):
                if group + v <= target:
                    groups[i] += v
                    if dfs(groups):
                        return True
                    groups[i] -= v
                if not group:
                    break
            nums.insert(0, v)
            return False

        return dfs([0]*k)

efficiency: HIGH
time complexity: O(k^n)
space complexity: O(n + k)
energy implications: LOW
explanation: This solution uses a depth-first search (DFS) to try to assign each number to one of the k subsets. It sorts the numbers in descending order to optimize the DFS by trying to place the largest numbers first. The DFS checks if the current number can be added to any of the existing groups without exceeding the target sum. If a valid placement is found, it continues with the next number. If no valid placement is found for the current number, it backtracks by re-inserting the number at its original position and returning False.
